Bug: the function adds an extra '+ 1' to the average. Fix:

def average(nums):
    total = 0
    for n in nums:
        total += n
    return total / len(nums)

Bug: the base case returns 0 instead of 1, which makes every factorial evaluate to 0. Fix:

def factorial(n):
    if n == 0:
        return 1
    return n * factorial(n - 1)

Bug: mutating 'items' (the list being iterated over) inside the loop via items.remove(item) causes skipped elements and incorrect results; also the logic is inverted (it removes on first-seen and appends on repeat, backwards from the intended dedup logic). Fix:

def remove_duplicates(items):
    result = []
    for item in items:
        if item not in result:
            result.append(item)
    return result

def most_frequent(items: list) -> object:
    counts = {}
    for item in items:
        counts[item] = counts.get(item, 0) + 1
    best = None
    best_count = -1
    for item in items:
        if counts[item] > best_count:
            best = item
            best_count = counts[item]
    return best

def merge_intervals(intervals):
    if not intervals:
        return []
    intervals = sorted(intervals, key=lambda x: x[0])
    merged = [intervals[0]]
    for start, end in intervals[1:]:
        last = merged[-1]
        if start <= last[1]:
            last[1] = max(last[1], end)
        else:
            merged.append([start, end])
    return merged
